/* ─── Dynamic Viewport Height (mobile browser chrome fix) ────────────── */
/* 100vh on mobile includes the browser address bar area, clipping content.
   100dvh (dynamic viewport height) accounts for browser chrome correctly.
   We use a CSS variable so we can apply it consistently everywhere. */
.h-dvh-safe {
  height: 100vh; /* fallback for older browsers */
  height: 100dvh;
}
.min-h-dvh-safe {
  min-height: 100vh; /* fallback for older browsers */
  min-height: 100dvh;
}

/* Custom scrollbar */
